import{_ as t,c as i,o as s,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"DM-связывание и контроль доступа: защита вашего AI-помощника | Учебник Clawdbot","description":"Узнайте о механизме защиты DM-связывания в Clawdbot. Изучите, как через CLI одобрять запросы на связывание от неизвестных отправителей, просматривать список ожидающих одобрения запросов и управлять списком разрешений. Этот учебник полностью описывает процесс связывания, использование CLI-команд, настройку политик доступа и лучшие практики безопасности, включая устранение распространенных ошибок и команду doctor.","frontmatter":{"title":"DM-связывание и контроль доступа: защита вашего AI-помощника | Учебник Clawdbot","sidebarTitle":"Управление доступом незнакомцев","subtitle":"DM-связывание и контроль доступа: защита вашего AI-помощника","description":"Узнайте о механизме защиты DM-связывания в Clawdbot. Изучите, как через CLI одобрять запросы на связывание от неизвестных отправителей, просматривать список ожидающих одобрения запросов и управлять списком разрешений. Этот учебник полностью описывает процесс связывания, использование CLI-команд, настройку политик доступа и лучшие практики безопасности, включая устранение распространенных ошибок и команду doctor.","tags":["Начинающий","Безопасность","Связывание","Контроль доступа"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"ru/moltbot/moltbot/start/pairing-approval/index.md","filePath":"ru/moltbot/moltbot/start/pairing-approval/index.md"}'),l={name:"ru/moltbot/moltbot/start/pairing-approval/index.md"};function o(n,a,r,d,p,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="dm-связывание-и-контроль-доступа-защита-вашего-ai-помощника" tabindex="-1">DM-связывание и контроль доступа: защита вашего AI-помощника <a class="header-anchor" href="#dm-связывание-и-контроль-доступа-защита-вашего-ai-помощника" aria-label="Permalink to &quot;DM-связывание и контроль доступа: защита вашего AI-помощника&quot;">​</a></h1><h2 id="что-вы-сможете-сделать" tabindex="-1">Что вы сможете сделать <a class="header-anchor" href="#что-вы-сможете-сделать" aria-label="Permalink to &quot;Что вы сможете сделать&quot;">​</a></h2><p>После завершения этого учебника вы сможете:</p><ul><li>✅ Понять механизм защиты DM-связывания по умолчанию</li><li>✅ Одобрять запросы на связывание от неизвестных отправителей</li><li>✅ Просматривать и управлять ожидающими одобрения запросами на связывание</li><li>✅ Настраивать различные политики доступа DM (pairing/allowlist/open)</li><li>✅ Запускать doctor для проверки конфигурации безопасности</li></ul><h2 id="ваша-текущая-ситуация" tabindex="-1">Ваша текущая ситуация <a class="header-anchor" href="#ваша-текущая-ситуация" aria-label="Permalink to &quot;Ваша текущая ситуация&quot;">​</a></h2><p>Возможно, вы только что настроили канал WhatsApp или Telegram и хотите общаться с AI-помощником, но столкнулись со следующими проблемами:</p><ul><li>&quot;Почему Clawdbot не отвечает на сообщения от незнакомцев?&quot;</li><li>&quot;Получил код связывания, не понимаю, что это значит&quot;</li><li>&quot;Хочу одобрить чей-то запрос, но не знаю, какую команду использовать&quot;</li><li>&quot;Как узнать, кто сейчас ожидает одобрения?&quot;</li></ul><p>Хорошая новость: <strong>Clawdbot по умолчанию включает защиту DM-связывания</strong>, это гарантирует, что только авторизованные вами отправители могут общаться с AI-помощником.</p><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><p>Когда вам нужно:</p><ul><li>🛡 <strong>Защитить приватность</strong>: гарантировать, что только доверенные лица могут общаться с AI-помощником</li><li>✅ <strong>Одобрить незнакомцев</strong>: разрешить новым отправителям доступ к вашему AI-помощнику</li><li>🔒 <strong>Строгий контроль доступа</strong>: ограничить права доступа конкретных пользователей</li><li>📋 <strong>Пакетное управление</strong>: просматривать и управлять всеми ожидающими одобрения запросами на связывание</li></ul><hr><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><h3 id="что-такое-dm-связывание" tabindex="-1">Что такое DM-связывание? <a class="header-anchor" href="#что-такое-dm-связывание" aria-label="Permalink to &quot;Что такое DM-связывание?&quot;">​</a></h3><p>Clawdbot подключается к реальным платформам сообщений (WhatsApp, Telegram, Slack и т.д.), и <strong>личные сообщения (DM) на этих платформах по умолчанию считаются ненадежным вводом</strong>.</p><p>Для защиты вашего AI-помощника Clawdbot предоставляет <strong>механизм связывания</strong>:</p><div class="info custom-block"><p class="custom-block-title">Процесс связывания</p><ol><li>Незнакомый отправитель отправляет вам сообщение</li><li>Clawdbot обнаруживает, что отправитель не авторизован</li><li>Clawdbot возвращает <strong>код связывания</strong> (8 символов)</li><li>Отправитель должен предоставить вам код связывания</li><li>Вы одобряете код через CLI</li><li>ID отправителя добавляется в список разрешений</li><li>Отправитель может нормально общаться с AI-помощником</li></ol></div><h3 id="политика-dm-по-умолчанию" tabindex="-1">Политика DM по умолчанию <a class="header-anchor" href="#политика-dm-по-умолчанию" aria-label="Permalink to &quot;Политика DM по умолчанию&quot;">​</a></h3><p><strong>Все каналы по умолчанию используют <code>dmPolicy=&quot;pairing&quot;</code></strong>, это означает:</p><table tabindex="0"><thead><tr><th>Политика</th><th>Поведение</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>Неизвестные отправители получают код связывания, сообщения не обрабатываются (по умолчанию)</td></tr><tr><td><code>allowlist</code></td><td>Разрешены только отправители из списка <code>allowFrom</code></td></tr><tr><td><code>open</code></td><td>Разрешены все отправители (требует явной конфигурации <code>&quot;*&quot;</code>)</td></tr><tr><td><code>disabled</code></td><td>Функция DM полностью отключена</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Предупреждение о безопасности</p><p>Режим <code>pairing</code> по умолчанию — самый безопасный выбор. Если у вас нет особых требований, не меняйте его на режим <code>open</code>.</p></div><hr><h2 id="🎒-подготовка" tabindex="-1">🎒 Подготовка <a class="header-anchor" href="#🎒-подготовка" aria-label="Permalink to &quot;🎒 Подготовка&quot;">​</a></h2><p>Убедитесь, что вы уже:</p><ul><li>[x] Завершили учебник <a href="./../getting-started/">Быстрый старт</a></li><li>[x] Завершили учебник <a href="./../gateway-startup/">Запуск Gateway</a></li><li>[x] Настроили хотя бы один канал сообщений (WhatsApp, Telegram, Slack и т.д.)</li><li>[x] Gateway запущен</li></ul><hr><h2 id="следуите-инструкциям" tabindex="-1">Следуйте инструкциям <a class="header-anchor" href="#следуите-инструкциям" aria-label="Permalink to &quot;Следуйте инструкциям&quot;">​</a></h2><h3 id="шаг-1-понять-происхождение-кода-связывания" tabindex="-1">Шаг 1: Понять происхождение кода связывания <a class="header-anchor" href="#шаг-1-понять-происхождение-кода-связывания" aria-label="Permalink to &quot;Шаг 1: Понять происхождение кода связывания&quot;">​</a></h3><p>Когда неизвестный отправитель отправляет сообщение вашему Clawdbot, он получит ответ, подобный следующему:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>Ключевые особенности кода связывания</strong> (источник: <code>src/pairing/pairing-store.ts</code>):</p><ul><li><strong>8 символов</strong>: удобно для ввода и запоминания</li><li><strong>Прописные буквы и цифры</strong>: избегает путаницы</li><li><strong>Исключение легко путаемых символов</strong>: не содержит 0, O, 1, I</li><li><strong>Срок действия 1 час</strong>: автоматически становится недействительным по истечении времени</li><li><strong>Максимум 3 ожидающих запроса</strong>: самый старый запрос автоматически очищается при превышении</li></ul><h3 id="шаг-2-просмотреть-список-ожидающих-запросов-на-связывание" tabindex="-1">Шаг 2: Просмотреть список ожидающих запросов на связывание <a class="header-anchor" href="#шаг-2-просмотреть-список-ожидающих-запросов-на-связывание" aria-label="Permalink to &quot;Шаг 2: Просмотреть список ожидающих запросов на связывание&quot;">​</a></h3><p>Запустите следующую команду в терминале:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>Если нет ожидающих одобрения запросов, вы увидите:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Поддерживаемые каналы</p><p>Функция связывания поддерживает следующие каналы:</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="шаг-3-одобрить-запрос-на-связывание" tabindex="-1">Шаг 3: Одобрить запрос на связывание <a class="header-anchor" href="#шаг-3-одобрить-запрос-на-связывание" aria-label="Permalink to &quot;Шаг 3: Одобрить запрос на связывание&quot;">​</a></h3><p>Используйте код связывания, предоставленный отправителем, для одобрения доступа:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Результат после одобрения</p><p>После одобрения ID отправителя (123456789) будет автоматически добавлен в список разрешений для этого канала и сохранен в: <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="шаг-4-уведомить-отправителя-опционально" tabindex="-1">Шаг 4: Уведомить отправителя (опционально) <a class="header-anchor" href="#шаг-4-уведомить-отправителя-опционально" aria-label="Permalink to &quot;Шаг 4: Уведомить отправителя (опционально)&quot;">​</a></h3><p>Если вы хотите автоматически уведомить отправителя, используйте флаг <code>--notify</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>Отправитель получит следующее сообщение (источник: <code>src/channels/plugins/pairing-message.ts</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>Примечание</strong>: Флаг <code>--notify</code> требует, чтобы Clawdbot Gateway был запущен, а канал находился в активном состоянии.</p><h3 id="шаг-5-проверить-что-отправитель-может-нормально-общаться" tabindex="-1">Шаг 5: Проверить, что отправитель может нормально общаться <a class="header-anchor" href="#шаг-5-проверить-что-отправитель-может-нормально-общаться" aria-label="Permalink to &quot;Шаг 5: Проверить, что отправитель может нормально общаться&quot;">​</a></h3><p>Попросите отправителя снова отправить сообщение, AI-помощник должен нормально ответить.</p><hr><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>Выполните следующие проверки для подтверждения правильности конфигурации:</p><ul><li>[ ] Команда <code>clawdbot pairing list &lt;channel&gt;</code> показывает ожидающие запросы</li><li>[ ] Команда <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> успешно одобряет</li><li>[ ] Одобренный отправитель может нормально общаться с AI-помощником</li><li>[ ] Код связывания автоматически истекает через 1 час (можно проверить, отправив еще одно сообщение)</li></ul><hr><h2 id="ошибки-и-их-решения" tabindex="-1">Ошибки и их решения <a class="header-anchor" href="#ошибки-и-их-решения" aria-label="Permalink to &quot;Ошибки и их решения&quot;">​</a></h2><h3 id="ошибка-1-код-связывания-не-наиден" tabindex="-1">Ошибка 1: Код связывания не найден <a class="header-anchor" href="#ошибка-1-код-связывания-не-наиден" aria-label="Permalink to &quot;Ошибка 1: Код связывания не найден&quot;">​</a></h3><p><strong>Сообщение об ошибке</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>Возможные причины</strong>:</p><ul><li>Код связывания уже истек (более 1 часа)</li><li>Код связывания введен неправильно (проверьте регистр)</li><li>Отправитель не отправлял сообщение (код связывания генерируется только при получении сообщения)</li></ul><p><strong>Решение</strong>:</p><ul><li>Попросите отправителя снова отправить сообщение, чтобы сгенерировать новый код связывания</li><li>Убедитесь, что код связывания скопирован правильно (обратите внимание на регистр)</li></ul><h3 id="ошибка-2-канал-не-поддерживает-связывание" tabindex="-1">Ошибка 2: Канал не поддерживает связывание <a class="header-anchor" href="#ошибка-2-канал-не-поддерживает-связывание" aria-label="Permalink to &quot;Ошибка 2: Канал не поддерживает связывание&quot;">​</a></h3><p><strong>Сообщение об ошибке</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>Возможные причины</strong>:</p><ul><li>Ошибка в написании названия канала</li><li>Канал не поддерживает функцию связывания</li></ul><p><strong>Решение</strong>:</p><ul><li>Запустите <code>clawdbot pairing list</code> для просмотра списка поддерживаемых каналов</li><li>Используйте правильное название канала</li></ul><h3 id="ошибка-3-сбои-уведомления" tabindex="-1">Ошибка 3: Сбой уведомления <a class="header-anchor" href="#ошибка-3-сбои-уведомления" aria-label="Permalink to &quot;Ошибка 3: Сбой уведомления&quot;">​</a></h3><p><strong>Сообщение об ошибке</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>Возможные причины</strong>:</p><ul><li>Gateway не запущен</li><li>Соединение с каналом прервано</li><li>Проблемы с сетью</li></ul><p><strong>Решение</strong>:</p><ul><li>Убедитесь, что Gateway запущен</li><li>Проверьте статус соединения канала: <code>clawdbot channels status</code></li><li>Не используйте флаг <code>--notify</code>, уведомите отправителя вручную</li></ul><hr><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>Этот учебник представил механизм защиты DM-связывания в Clawdbot:</p><ul><li><strong>Безопасность по умолчанию</strong>: все каналы по умолчанию используют режим <code>pairing</code>, защищая ваш AI-помощник</li><li><strong>Процесс связывания</strong>: неизвестные отправители получают 8-значный код связывания, вам нужно одобрить его через CLI</li><li><strong>Команды управления</strong>: <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>: просмотр ожидающих запросов</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>: одобрение связывания</li></ul></li><li><strong>Место хранения</strong>: список разрешений хранится в <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>Автоматическое истечение</strong>: запросы на связывание автоматически становятся недействительными через 1 час</li></ul><p>Помните: <strong>механизм связывания — это фундамент безопасности Clawdbot</strong>, гарантирующий, что только авторизованные вами лица могут общаться с AI-помощником.</p><hr><h2 id="следующии-урок" tabindex="-1">Следующий урок <a class="header-anchor" href="#следующии-урок" aria-label="Permalink to &quot;Следующий урок&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../faq/troubleshooting/">Устранение неполадок: решение распространенных проблем</a></strong>.</p><p>Вы узнаете:</p><ul><li>Быстрая диагностика и проверка состояния системы</li><li>Решение проблем запуска Gateway, подключения каналов, ошибок аутентификации и т.д.</li><li>Методы устранения неудачных вызовов инструментов и оптимизации производительности</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Генерация кода связывания (8 знаков, исключение путаемых символов)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>Хранение запросов на связывание и TTL (1 час)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>Команда одобрения связывания</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>Генерация сообщения с кодом связывания</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>Хранение списка разрешений</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>Список каналов, поддерживающих <code>pairing</code></td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>Политика DM по умолчанию (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>: длина кода связывания</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>: набор символов кода связывания (исключая 0O1I)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>: срок действия запроса на связывание (1 час)</li><li><code>PAIRING_PENDING_MAX = 3</code>: максимальное количество ожидающих запросов</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>approveChannelPairingCode()</code>: одобрение кода связывания и добавление в список разрешений</li><li><code>listChannelPairingRequests()</code>: просмотр ожидающих запросов на связывание</li><li><code>upsertChannelPairingRequest()</code>: создание или обновление запроса на связывание</li><li><code>addChannelAllowFromStoreEntry()</code>: добавление отправителя в список разрешений</li></ul></details>`,92)])])}const b=t(l,[["render",o]]);export{g as __pageData,b as default};
